// TestZeroConfigRetryEscalationPolicy verifies the retry/escalation policy
// composes correctly when the loop starts from the new metadata-driven
// "profile=cheap by default" path (commit 3ddf3d52, ddx-b2c9a245). It is a
// follow-up to AC6 of ddx-b790449b: confirm that transient failures retry
// within the cheap tier (no escalation) and substantive failures escalate
// cheap -> standard -> smart.
//
// The test drives a simulated tier ladder using the real escalation
// primitives (InferTier, IsInfrastructureFailure, ShouldEscalate,
// TierToProfile, BuildEscalationSummary). It does not require a running
// agent service or harness binary.
func TestZeroConfigRetryEscalationPolicy(t *testing.T) {
	// 1. Unflagged bead: no tier label, no kind, short description.
	// InferTier must default to cheap so the loop starts at the cheap
	// tier instead of the previous always-cheap fallback or the SD-024
	// "no profile" path.
	b := &bead.Bead{
		ID:          "ddx-zero-config-001",
		Title:       "trivial cleanup, unflagged",
		Description: "minor doc tweak",
	}
	startTier := escalation.InferTier(b)
	require.Equal(t, escalation.TierCheap, startTier,
		"unflagged bead must infer cheap tier (zero-config default)")
	require.Equal(t, "cheap", escalation.TierToProfile(startTier),
		"cheap tier maps to 'cheap' profile string consumed by LoadAndResolve")

	// 2. Transient infrastructure failure on cheap tier (e.g. 502 from
	// the inference host). The policy is: do NOT escalate; defer with a
	// retry-after and try the same tier again. The model wasn't given
	// a fair chance, so escalation budget must not be consumed.
	transientStatus := ExecuteBeadStatusExecutionFailed
	transientDetail := "provider 502 Bad Gateway: connection refused"
	require.True(t,
		escalation.IsInfrastructureFailure(transientStatus, transientDetail),
		"502 Bad Gateway on execution_failed must be classified as infrastructure failure")
	require.True(t,
		escalation.ShouldEscalate(transientStatus),
		"execution_failed itself remains escalatable; the loop must consult IsInfrastructureFailure first to defer-vs-escalate")

	// Loop ordering invariant: when IsInfrastructureFailure is true the
	// loop body defers (retry-after) instead of advancing the tier. The
	// tier on the next attempt is therefore unchanged.
	tierAfterTransient := startTier
	require.Equal(t, escalation.TierCheap, tierAfterTransient,
		"transient failure must not advance the tier ladder")

	// 3. Substantive failure on cheap tier (e.g. tests failed). Policy:
	// escalate to the next tier (standard).
	substantiveStatus := ExecuteBeadStatusExecutionFailed
	substantiveDetail := "TestFoo failed: assertion mismatch"
	require.False(t,
		escalation.IsInfrastructureFailure(substantiveStatus, substantiveDetail),
		"a model-capability failure detail must not match infrastructure patterns")
	require.True(t,
		escalation.ShouldEscalate(substantiveStatus),
		"substantive execution_failed must escalate")
	tierAfterCheapSubstantive := nextTier(tierAfterTransient)
	require.Equal(t, escalation.TierStandard, tierAfterCheapSubstantive,
		"cheap -> standard escalation step")

	// 4. Substantive failure on standard tier. Policy: escalate to smart.
	standardStatus := ExecuteBeadStatusPostRunCheckFailed
	require.True(t,
		escalation.ShouldEscalate(standardStatus),
		"post_run_check_failed escalates")
	tierAfterStandardSubstantive := nextTier(tierAfterCheapSubstantive)
	require.Equal(t, escalation.TierSmart, tierAfterStandardSubstantive,
		"standard -> smart escalation step")

	// 5. Smart tier succeeds. Build the escalation summary and verify
	// the full trail is recorded with winning_tier=smart and the cheap
	// transient attempt counted as wasted-but-not-escalating-budget.
	attempts := []escalation.TierAttemptRecord{
		{Tier: string(escalation.TierCheap), Harness: "agent", Model: "cheap-model", Status: transientStatus, CostUSD: 0.0, DurationMS: 800},
		{Tier: string(escalation.TierCheap), Harness: "agent", Model: "cheap-model", Status: substantiveStatus, CostUSD: 0.02, DurationMS: 1500},
		{Tier: string(escalation.TierStandard), Harness: "codex", Model: "standard-model", Status: standardStatus, CostUSD: 0.15, DurationMS: 3400},
		{Tier: string(escalation.TierSmart), Harness: "claude", Model: "smart-model", Status: escalation.SuccessStatus, CostUSD: 0.80, DurationMS: 9000},
	}
	summary := escalation.BuildEscalationSummary(attempts, string(escalation.TierSmart))
	require.Equal(t, string(escalation.TierSmart), summary.WinningTier,
		"smart tier won the escalation")
	require.Len(t, summary.TiersAttempted, 4,
		"trail records all attempts including the deferred-transient cheap attempt")
	assert.InDelta(t, 0.97, summary.TotalCostUSD, 1e-9)
	assert.InDelta(t, 0.17, summary.WastedCostUSD, 1e-9,
		"cheap-substantive (0.02) + standard (0.15) wasted; cheap-transient billed $0; smart succeeded")
	assert.Equal(t, string(escalation.TierCheap), summary.TiersAttempted[0].Tier,
		"first attempt was cheap (the new metadata-driven default)")
	assert.Equal(t, string(escalation.TierSmart), summary.TiersAttempted[3].Tier,
		"final attempt was smart (top of ladder)")
}

// TestZeroConfigEscalationSummaryEventBody verifies the escalation summary
// is emitted as a kind:escalation-summary bead event when the cheap-default
// ladder runs to completion. This is the operator-visible artifact of the
// retry/escalation policy.
func TestZeroConfigEscalationSummaryEventBody(t *testing.T) {
	store := bead.NewStore(t.TempDir())
	require.NoError(t, store.Init())
	target := &bead.Bead{ID: "ddx-zero-config-002", Title: "cheap-default ladder", Priority: 0}
	require.NoError(t, store.Create(target))

	attempts := []escalation.TierAttemptRecord{
		{Tier: string(escalation.TierCheap), Status: ExecuteBeadStatusExecutionFailed, CostUSD: 0.01, DurationMS: 1000},
		{Tier: string(escalation.TierStandard), Status: ExecuteBeadStatusExecutionFailed, CostUSD: 0.10, DurationMS: 2000},
		{Tier: string(escalation.TierSmart), Status: escalation.SuccessStatus, CostUSD: 0.50, DurationMS: 4000},
	}
	require.NoError(t,
		escalation.AppendEscalationSummaryEvent(
			store, target.ID, "test-worker", attempts, string(escalation.TierSmart), time.Unix(1, 0).UTC()))

	events, err := store.Events(target.ID)
	require.NoError(t, err)
	var found *bead.BeadEvent
	for i := range events {
		if events[i].Kind == "escalation-summary" {
			found = &events[i]
			break
		}
	}
	require.NotNil(t, found, "escalation-summary event must be appended for the cheap-default ladder run")
	assert.Contains(t, found.Summary, "winning_tier=smart")
	assert.Contains(t, found.Summary, "attempts=3")
	assert.Contains(t, found.Body, `"tier":"cheap"`,
		"summary body records cheap as the first-attempted tier (zero-config default)")
	assert.Contains(t, found.Body, `"tier":"standard"`)
	assert.Contains(t, found.Body, `"tier":"smart"`)
}

// nextTier advances one rung up the cheap -> standard -> smart ladder.
// Mirrors the implicit ladder used by the execute-loop when escalating
// beyond a substantive failure. Smart is the top; further calls stay
// at smart (callers exhaust escalation when ShouldEscalate fires at smart).
func nextTier(t escalation.ModelTier) escalation.ModelTier {
	switch t {
	case escalation.TierCheap:
		return escalation.TierStandard
	case escalation.TierStandard:
		return escalation.TierSmart
	default:
		return escalation.TierSmart
	}
}

package server

import (
	"context"
	"strings"
	"sync/atomic"
	"testing"

	"github.com/DocumentDrivenDX/ddx/internal/agent"
	"github.com/DocumentDrivenDX/ddx/internal/escalation"
)

// These tests exercise the cost-cap and infrastructure-failure wiring
// used by runWorker's executor closure (see workers.go around the
// `executor := agent.ExecuteBeadExecutorFunc(...)` block).
//
// The closure itself is built inline (so it cannot be unit-tested
// directly), but we exercise the same composition pattern here against
// a fake inner attempt to assert:
//
//  1. When accumulated cost exceeds the cap, the next executor call
//     returns the cap-tripped error WITHOUT invoking the inner attempt.
//  2. Infrastructure failures are detected by IsInfrastructureFailure
//     and short-circuit before the next-tier escalation step.
//
// Patterns mirror the closures in cli/internal/server/workers.go
// (ddx-785d02f7).

type fakeServerAttempt struct {
	calls   atomic.Int32
	reports []agent.ExecuteBeadReport
}

func (f *fakeServerAttempt) next(_ string) agent.ExecuteBeadReport {
	idx := f.calls.Add(1) - 1
	if int(idx) >= len(f.reports) {
		return f.reports[len(f.reports)-1]
	}
	return f.reports[idx]
}

func wrapServerExecutor(tracker *escalation.CostCapTracker, inner func(beadID string) agent.ExecuteBeadReport) agent.ExecuteBeadExecutorFunc {
	return func(ctx context.Context, beadID string) (agent.ExecuteBeadReport, error) {
		if detail, capped := tracker.Tripped(); capped {
			return agent.ExecuteBeadReport{
				BeadID: beadID,
				Status: agent.ExecuteBeadStatusExecutionFailed,
				Detail: detail,
			}, nil
		}
		report := inner(beadID)
		tracker.Add(report.Harness, report.CostUSD)
		if detail, capped := tracker.Tripped(); capped {
			return agent.ExecuteBeadReport{
				BeadID: beadID,
				Status: agent.ExecuteBeadStatusExecutionFailed,
				Detail: detail,
			}, nil
		}
		return report, nil
	}
}

// TestWorkerExecutorCostCap_StopsAfterCap asserts the server worker's
// cost-cap logic halts further bead claiming once accumulated billed
// spend reaches the cap.
func TestWorkerExecutorCostCap_StopsAfterCap(t *testing.T) {
	tracker := escalation.NewCostCapTracker(5.0, func(string) bool { return true })

	fake := &fakeServerAttempt{
		reports: []agent.ExecuteBeadReport{
			{BeadID: "ddx-1", Harness: "openrouter", Status: agent.ExecuteBeadStatusSuccess, CostUSD: 3.0},
			{BeadID: "ddx-2", Harness: "openrouter", Status: agent.ExecuteBeadStatusSuccess, CostUSD: 3.0},
			{BeadID: "ddx-3", Harness: "openrouter", Status: agent.ExecuteBeadStatusSuccess, CostUSD: 1.0},
		},
	}
	exec := wrapServerExecutor(tracker, fake.next)

	// First call: $3 < $5 cap.
	if r, err := exec(context.Background(), "ddx-1"); err != nil || r.Status != agent.ExecuteBeadStatusSuccess {
		t.Fatalf("call 1: status=%s err=%v", r.Status, err)
	}
	// Second call: $6 >= $5; post-attempt cap fires.
	r2, _ := exec(context.Background(), "ddx-2")
	if r2.Status != agent.ExecuteBeadStatusExecutionFailed {
		t.Fatalf("call 2 should trip cap; status=%s", r2.Status)
	}
	if !strings.Contains(r2.Detail, "cost cap reached") {
		t.Fatalf("call 2 detail = %q", r2.Detail)
	}

	callsBefore := fake.calls.Load()
	// Third call: cap-on-entry blocks before invoking inner.
	r3, _ := exec(context.Background(), "ddx-3")
	if r3.Status != agent.ExecuteBeadStatusExecutionFailed {
		t.Fatalf("call 3 should be cap-tripped on entry; status=%s", r3.Status)
	}
	if r3.BeadID != "ddx-3" {
		t.Fatalf("cap-tripped report missing beadID: %q", r3.BeadID)
	}
	if got := fake.calls.Load(); got != callsBefore {
		t.Fatalf("inner attempt was invoked despite cap; calls %d -> %d", callsBefore, got)
	}
}

// TestWorkerExecutorCostCap_SubscriptionDoesNotCount asserts that
// subscription/local-provider costs do not contribute to the cap, even
// at huge reported CostUSD values.
func TestWorkerExecutorCostCap_SubscriptionDoesNotCount(t *testing.T) {
	tracker := escalation.NewCostCapTracker(10.0, func(name string) bool {
		// Only "openrouter" counts; everything else is local/subscription.
		return name == "openrouter"
	})

	fake := &fakeServerAttempt{
		reports: []agent.ExecuteBeadReport{
			{BeadID: "ddx-x", Harness: "claude", Status: agent.ExecuteBeadStatusSuccess, CostUSD: 1000.0},
			{BeadID: "ddx-y", Harness: "openrouter", Status: agent.ExecuteBeadStatusSuccess, CostUSD: 1.0},
		},
	}
	exec := wrapServerExecutor(tracker, fake.next)

	for _, id := range []string{"ddx-x", "ddx-y"} {
		r, _ := exec(context.Background(), id)
		if r.Status != agent.ExecuteBeadStatusSuccess {
			t.Fatalf("call %s: subscription/billed mix should not trip; status=%s", id, r.Status)
		}
	}
	if got := tracker.Spent(); got != 1.0 {
		t.Fatalf("Spent = %.2f, want 1.0 (only openrouter counts)", got)
	}
}

// TestWorkerInfrastructureFailureDoesNotEscalate asserts the contract
// the server tier-loop relies on: IsInfrastructureFailure flags
// transient provider failures (so the loop defers with retry-after)
// without consuming escalation budget, while real model-capability
// failures fall through to the next-tier path.
func TestWorkerInfrastructureFailureDoesNotEscalate(t *testing.T) {
	cases := []struct {
		name      string
		status    string
		detail    string
		wantInfra bool
	}{
		{"503 from provider triggers defer", agent.ExecuteBeadStatusExecutionFailed, "503 service unavailable", true},
		{"i/o timeout triggers defer", agent.ExecuteBeadStatusExecutionFailed, "Get http://x: i/o timeout", true},
		{"missing binary triggers defer", agent.ExecuteBeadStatusExecutionFailed, `exec: "claude": executable file not found in $PATH`, true},
		{"build failure does NOT defer (escalates)", agent.ExecuteBeadStatusExecutionFailed, "build error: missing import", false},
		{"structural validation escalates but is not infra", "structural_validation_failed", "503 service unavailable", false},
	}
	for _, tc := range cases {
		t.Run(tc.name, func(t *testing.T) {
			got := escalation.IsInfrastructureFailure(tc.status, tc.detail)
			if got != tc.wantInfra {
				t.Fatalf("IsInfrastructureFailure(%q, %q) = %v, want %v", tc.status, tc.detail, got, tc.wantInfra)
			}
			// The loop ordering invariant: when IsInfrastructureFailure
			// returns true, ShouldEscalate must also be true (otherwise
			// the infra branch is unreachable from the tier loop).
			if tc.wantInfra && !escalation.ShouldEscalate(tc.status) {
				t.Fatalf("infra-failure case %q has !ShouldEscalate; loop ordering invariant broken", tc.name)
			}
		})
	}
}

package escalation

import (
	"encoding/json"
	"testing"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

// --- Local mirrors of agent.ExecuteBeadStatus* so these tests do not import
// the agent package. Their string values must stay in sync with
// cli/internal/agent/execute_bead_status.go; the agent package's
// TestEscalatableStatusesMatchAgentVocab guards against drift for the
// statuses that drive escalation.
const (
	statusExecutionFailed            = "execution_failed"
	statusNoChanges                  = "no_changes"
	statusPostRunCheckFailed         = "post_run_check_failed"
	statusLandConflict               = "land_conflict"
	statusStructuralValidationFailed = "structural_validation_failed"
	statusAlreadySatisfied           = "already_satisfied"
	statusSuccess                    = "success"
)

// --- EscalationSummary ---

// recordingAppender captures events appended by AppendEscalationSummaryEvent
// so tests can assert on the kind, summary, and JSON body.
type recordingAppender struct {
	events []struct {
		id    string
		event bead.BeadEvent
	}
}

func (r *recordingAppender) AppendEvent(id string, event bead.BeadEvent) error {
	r.events = append(r.events, struct {
		id    string
		event bead.BeadEvent
	}{id: id, event: event})
	return nil
}

// TestEscalationSummary exercises the 3-tier escalation scenario from the
// bead: cheap fails, standard fails, smart succeeds. The emitted
// kind:escalation-summary event body must contain all three tier records
// with correct statuses, costs, and a winning_tier/wasted_cost_usd roll-up.
func TestEscalationSummary(t *testing.T) {
	attempts := []TierAttemptRecord{
		{Tier: "cheap", Harness: "agent", Model: "cheap-model", Status: statusExecutionFailed, CostUSD: 0.02, DurationMS: 1200},
		{Tier: "standard", Harness: "codex", Model: "standard-model", Status: statusNoChanges, CostUSD: 0.15, DurationMS: 3400},
		{Tier: "smart", Harness: "claude", Model: "smart-model", Status: statusSuccess, CostUSD: 0.80, DurationMS: 9000},
	}

	summary := BuildEscalationSummary(attempts, "smart")
	require.Equal(t, "smart", summary.WinningTier)
	require.Len(t, summary.TiersAttempted, 3)
	assert.InDelta(t, 0.97, summary.TotalCostUSD, 1e-9)
	assert.InDelta(t, 0.17, summary.WastedCostUSD, 1e-9, "cheap (0.02) + standard (0.15) wasted, smart succeeded")
	assert.Equal(t, "cheap", summary.TiersAttempted[0].Tier)
	assert.Equal(t, statusExecutionFailed, summary.TiersAttempted[0].Status)
	assert.Equal(t, statusNoChanges, summary.TiersAttempted[1].Status)
	assert.Equal(t, statusSuccess, summary.TiersAttempted[2].Status)

	// Now wire through AppendEscalationSummaryEvent and verify the emitted
	// event has kind:escalation-summary, a summary line, and a JSON body
	// that round-trips to the same EscalationSummary.
	appender := &recordingAppender{}
	err := AppendEscalationSummaryEvent(appender, "ddx-test-1", "test-actor", attempts, "smart", time.Unix(1, 0).UTC())
	require.NoError(t, err)
	require.Len(t, appender.events, 1)

	ev := appender.events[0]
	assert.Equal(t, "ddx-test-1", ev.id)
	assert.Equal(t, "escalation-summary", ev.event.Kind)
	assert.Equal(t, "test-actor", ev.event.Actor)
	assert.Contains(t, ev.event.Summary, "winning_tier=smart")
	assert.Contains(t, ev.event.Summary, "attempts=3")

	var decoded EscalationSummary
	require.NoError(t, json.Unmarshal([]byte(ev.event.Body), &decoded))
	assert.Equal(t, "smart", decoded.WinningTier)
	require.Len(t, decoded.TiersAttempted, 3)
	assert.Equal(t, "cheap", decoded.TiersAttempted[0].Tier)
	assert.Equal(t, "agent", decoded.TiersAttempted[0].Harness)
	assert.Equal(t, "cheap-model", decoded.TiersAttempted[0].Model)
	assert.Equal(t, statusExecutionFailed, decoded.TiersAttempted[0].Status)
	assert.InDelta(t, 0.02, decoded.TiersAttempted[0].CostUSD, 1e-9)
	assert.Equal(t, int64(1200), decoded.TiersAttempted[0].DurationMS)
	assert.InDelta(t, 0.97, decoded.TotalCostUSD, 1e-9)
	assert.InDelta(t, 0.17, decoded.WastedCostUSD, 1e-9)
}

// TestEscalationSummaryExhausted verifies the exhausted case (no tier
// succeeded): winning_tier is "exhausted" and all costs are wasted.
func TestEscalationSummaryExhausted(t *testing.T) {
	attempts := []TierAttemptRecord{
		{Tier: "cheap", Harness: "agent", Model: "c", Status: statusExecutionFailed, CostUSD: 0.01, DurationMS: 900},
		{Tier: "smart", Harness: "claude", Model: "s", Status: statusExecutionFailed, CostUSD: 0.50, DurationMS: 7000},
	}
	summary := BuildEscalationSummary(attempts, "")
	assert.Equal(t, EscalationWinningExhausted, summary.WinningTier)
	assert.InDelta(t, 0.51, summary.TotalCostUSD, 1e-9)
	assert.InDelta(t, 0.51, summary.WastedCostUSD, 1e-9, "every attempt wasted when no tier succeeded")
}

// TestEscalationSummaryBuildSourceSliceIndependent verifies the attempts
// slice in the returned summary is independent of the caller's slice —
// mutating the caller's slice must not change the summary.
func TestEscalationSummaryBuildSourceSliceIndependent(t *testing.T) {
	attempts := []TierAttemptRecord{
		{Tier: "cheap", Status: statusSuccess, CostUSD: 0.05},
	}
	summary := BuildEscalationSummary(attempts, "cheap")
	attempts[0].Tier = "mutated"
	assert.Equal(t, "cheap", summary.TiersAttempted[0].Tier, "summary must hold an independent copy of attempts")
}

// --- ShouldEscalate ---

func TestShouldEscalateExecutionFailed(t *testing.T) {
	assert.True(t, ShouldEscalate(statusExecutionFailed))
}

func TestShouldEscalateNoChangesIsFalse(t *testing.T) {
	assert.False(t, ShouldEscalate(statusNoChanges))
}

func TestShouldEscalatePostRunCheckFailed(t *testing.T) {
	assert.True(t, ShouldEscalate(statusPostRunCheckFailed))
}

func TestShouldEscalateLandConflict(t *testing.T) {
	assert.True(t, ShouldEscalate(statusLandConflict))
}

func TestShouldEscalateSuccessIsFalse(t *testing.T) {
	assert.False(t, ShouldEscalate(statusSuccess))
}

func TestShouldEscalateStructuralValidationIsTrue(t *testing.T) {
	assert.True(t, ShouldEscalate(statusStructuralValidationFailed))
}

func TestShouldEscalateAlreadySatisfiedIsFalse(t *testing.T) {
	assert.False(t, ShouldEscalate(statusAlreadySatisfied))
}

// --- FormatTierAttemptBody ---

func TestFormatTierAttemptBodyWithAllFields(t *testing.T) {
	body := FormatTierAttemptBody("cheap", "claude", "claude-haiku-4-5", "ok", "execution failed")
	assert.Contains(t, body, "tier=cheap")
	assert.Contains(t, body, "harness=claude")
	assert.Contains(t, body, "model=claude-haiku-4-5")
	assert.Contains(t, body, "probe=ok")
	assert.Contains(t, body, "execution failed")
}

func TestFormatTierAttemptBodyNoProbeNoDetail(t *testing.T) {
	body := FormatTierAttemptBody("standard", "codex", "gpt-5.4", "", "")
	assert.Contains(t, body, "tier=standard")
	assert.NotContains(t, body, "probe=")
}
